const resp = $input.first().json;
let conteudo = '';
try { conteudo = resp.choices[0].message.content; } catch (e) { conteudo = ''; }
if (!conteudo) conteudo = 'Desculpe, não consegui responder agora. Vou encaminhar sua mensagem para a equipe.';
const prep = $('Prepara Prompt').first().json;
return [{ json: { conversa_id: prep.conversa_id, conteudo } }];
